import axios from 'axios';

// АВТОМАТИЧЕСКОЕ ОПРЕДЕЛЕНИЕ БАЗОВОГО URL
const getBaseURL = () => {
  // Если мы в development режиме (npm start)
  if (process.env.NODE_ENV === 'development') {
    return 'http://localhost:8080/area-backend/api';  // Раздельный режим
  }
  // Если в production (в WAR файле)
  return window.location.origin + '/area-app/api';  // Единый WAR
};

const API_BASE = getBaseURL();
console.log('🔧 API Base URL:', API_BASE);

const api = axios.create({
  baseURL: API_BASE,
  headers: {
    'Content-Type': 'application/json'
  }
});

// Интерцептор для добавления токена
api.interceptors.request.use(config => {
  const token = localStorage.getItem('token');
  console.log('🔄 Interceptor: token found?', !!token);

  if (token) {
    config.headers.Authorization = token;
    console.log('🔄 Установлен заголовок Authorization:', token.substring(0, 10) + '...');
  }

  return config;
});

// Интерцептор для обработки ошибок
api.interceptors.response.use(
  response => response,
  error => {
    console.error('API Error:', error.response?.status, error.message);

    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('username');
      window.location.hash = '#/login';
    }
    return Promise.reject(error);
  }
);

export const authAPI = {
  login: async (username, password) => {
    try {
      console.log('🔐 Login attempt to:', API_BASE + '/login');
      const body = { username, password };
      const response = await api.post('/login', body);

      console.log('✅ Login response:', response.data);

      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('username', response.data.username);
        return { success: true, data: response.data };
      }
    } catch (error) {
      console.error('❌ Login error:', error);
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка авторизации'
      };
    }
  },

  register: async (username, password) => {
    try {
      const body = { username, password };
      const response = await api.post('/register', body);

      if (response.data.token) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('username', response.data.username);
        return { success: true, data: response.data };
      }
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка регистрации'
      };
    }
  },

  logout: async () => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        await api.post('/logout', {}, {
          headers: { Authorization: token }
        });
      } catch (error) {
        console.log('Logout completed (ignoring errors)');
      }
    }
    localStorage.removeItem('token');
    localStorage.removeItem('username');
  }
};

export const pointAPI = {
  checkPoint: async (x, y, r) => {
    try {
      const body = { x, y, r };
      const response = await api.post('/check', body);
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка проверки точки'
      };
    }
  },

  getResults: async () => {
    try {
      const response = await api.get('/results');
      return { success: true, data: response.data };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка загрузки результатов'
      };
    }
  },

  clearResults: async () => {
    try {
      await api.delete('/results');
      return { success: true };
    } catch (error) {
      return {
        success: false,
        message: error.response?.data?.error || 'Ошибка очистки'
      };
    }
  }
};

export const checkAuth = async () => {
  const token = localStorage.getItem('token');
  if (!token) return false;

  // Можно добавить проверку токена на сервере
  // try {
  //   const response = await api.get('/validate');
  //   return response.data.valid;
  // } catch {
  //   return false;
  // }

  return true;  // Пока просто проверяем наличие токена
};

export default api;
